targets.expr:
(
  oracledb_compute_stats_value{server="$server", name="sorts (memory)"}
  / 
  on(server, instance, job) 
  (
    sum by (server, instance, job) (oracledb_compute_stats_value{server="$server", name=~"sorts.*"})
  )
) * 100

(
  oracledb_sga_stats_free_bytes{server="$server", pool="shared pool"} 
  / on(server, instance) group_left 
  oracledb_db_system_value{server="$server", name="sga_max_size"}
) * 100
